#include <iostream>
#include <stack>
using namespace std;
stack<int> p;
int q,n,num=0;
int main()
{
    cin>>q;
    for(int i=0;i<=q-1;i++)
    {
        int pushed[100005],poped[100005];
        cin>>n;
        for(int j=0;j<=n-1;j++)
        {
            cin>>pushed[j];
        }
        for(int j=0;j<=n-1;j++)
        {
            cin>>poped[j];
        }
        for(int j=0;j<=n-1;j++)
        {
            p.push(pushed[j]);
            while(p.top()==poped[num])
            {
                p.pop();
                num++;
                if(p.empty())
                {
                    break;
                }
            }
        }
        if(p.empty())
        {
            cout<<"Yes"<<endl;
        }
        else
        {
            cout<<"No"<<endl;
            while(!(p.empty()))
            {
                p.pop();
            }
        }
        num=0;
    }
    return 0;
}
